DESCRIPTION = 'ゴルフスコアを無料で記録・管理・グラフ分析。ラウンドごとの成績・ベストスコア・ハンデキャップを自動計算。登録不要ですぐ使える。'
JS_CODE = '// ===== データ管理 =====\nconst STORE_KEY = \'golf_rounds_v1\';\nconst PAR_DEFAULT = [4,3,4,5,4,3,4,5,4, 4,3,4,5,4,3,5,4,4]; // 標準的なパー配列\n\nfunction getRounds() {\n    try { return JSON.parse(localStorage.getItem(STORE_KEY) || \'[]\'); }\n    catch(e) { return []; }\n}\nfunction saveRounds(rounds) {\n    try { localStorage.setItem(STORE_KEY, JSON.stringify(rounds)); }\n    catch(e) { alert(\'保存容量が不足しています。古いデータを削除してください。\'); }\n}\n\n// ===== ホール入力 =====\nfunction buildHoleInputs() {\n    const outEl = document.getElementById(\'holes-out\');\n    const inEl  = document.getElementById(\'holes-in\');\n    outEl.innerHTML = \'\';\n    inEl.innerHTML  = \'\';\n    for (let h = 1; h <= 18; h++) {\n        const par = PAR_DEFAULT[h-1];\n        const el  = document.createElement(\'div\');\n        el.className = \'hole-box\';\n        el.innerHTML = `<div class="hole-num">${h}</div><div class="hole-par">P${par}</div>\n            <input class="hole-input" type="number" id="h${h}" min="1" max="15" placeholder="-"\n                   oninput="colorHole(this,${par});updateTotals()" aria-label="-">`;\n        (h <= 9 ? outEl : inEl).appendChild(el);\n    }\n    updateTotals();\n}\n\nfunction colorHole(inp, par) {\n    const v = parseInt(inp.value);\n    inp.className = \'hole-input\';\n    if (!v) return;\n    if (v <= par - 2) inp.classList.add(\'eagle\');\n    else if (v === par - 1) inp.classList.add(\'birdie\');\n    else if (v === par) inp.classList.add(\'par-score\');\n    else if (v === par + 1) inp.classList.add(\'bogey\');\n    else if (v === par + 2) inp.classList.add(\'double\');\n    else inp.classList.add(\'triple\');\n}\n\nfunction updateTotals() {\n    let out = 0, inn = 0, outPar = 0, inPar = 0;\n    for (let h = 1; h <= 9; h++) {\n        const v = parseInt(document.getElementById(\'h\'+h)?.value || 0); if (v) out += v;\n        outPar += PAR_DEFAULT[h-1];\n    }\n    for (let h = 10; h <= 18; h++) {\n        const v = parseInt(document.getElementById(\'h\'+h)?.value || 0); if (v) inn += v;\n        inPar += PAR_DEFAULT[h-1];\n    }\n    const total = out + inn;\n    const totalPar = outPar + inPar;\n    document.getElementById(\'hole-totals\').innerHTML = `\n        <div><div style="font-size:0.7em;color:#64748b;">OUT</div><div>${out||\'-\'}<span style="font-size:0.7em;color:#94a3b8;"> / P${outPar}</span></div></div>\n        <div><div style="font-size:0.7em;color:#64748b;">IN</div><div>${inn||\'-\'}<span style="font-size:0.7em;color:#94a3b8;"> / P${inPar}</span></div></div>\n        <div><div style="font-size:0.7em;color:#64748b;">TOTAL</div><div style="color:#166534;">${total||\'-\'}<span style="font-size:0.7em;color:#94a3b8;"> / P${totalPar}</span></div></div>`;\n}\n\nfunction toggleMode() {\n    const simple = document.getElementById(\'simple-mode\').checked;\n    document.getElementById(\'hole-inputs-wrap\').style.display = simple ? \'none\' : \'block\';\n    document.getElementById(\'simple-input-wrap\').style.display = simple ? \'block\' : \'none\';\n}\n\n// ===== 記録 =====\nfunction saveRound() {\n    const date    = document.getElementById(\'inp-date\').value;\n    const course  = document.getElementById(\'inp-course\').value.trim();\n    const type    = document.getElementById(\'inp-type\').value;\n    const weather = document.getElementById(\'inp-weather\').value;\n    const memo    = document.getElementById(\'inp-memo\').value.trim();\n    const partner = document.getElementById(\'inp-partner\').value.trim();\n    const simple  = document.getElementById(\'simple-mode\').checked;\n\n    if (!date || !course) { alert(\'日付とコース名を入力してください。\'); return; }\n\n    let holes = [];\n    let score = 0;\n\n    if (simple) {\n        score = parseInt(document.getElementById(\'inp-simple-score\').value);\n        if (!score || score < 40 || score > 200) { alert(\'スコアを正しく入力してください（40〜200）。\'); return; }\n        holes = [];\n    } else {\n        for (let h = 1; h <= 18; h++) {\n            const v = parseInt(document.getElementById(\'h\'+h)?.value || 0);\n            holes.push(v || 0);\n        }\n        score = holes.reduce((a,b) => a+b, 0);\n        const filled = holes.filter(v => v > 0).lengt'
